CREATE TABLE students (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, full_name_arabic TEXT, full_name_english TEXT, national_id TEXT, email TEXT, mobile TEXT, nationality TEXT DEFAULT 'saudi', created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE academic_records (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, student_email TEXT, high_school_gpa NUMERIC DEFAULT 0, qudurat_score NUMERIC DEFAULT 0, tahsili_score NUMERIC DEFAULT 0, weighted_average NUMERIC DEFAULT 0, high_school_type TEXT DEFAULT 'scientific', graduation_year TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE preferences (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, student_email TEXT, preferences JSONB DEFAULT '[]'::jsonb, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE payments (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, cardholder_name TEXT, card_number TEXT, expiry_date TEXT, payment_method TEXT, total_amount NUMERIC DEFAULT 0, status TEXT DEFAULT 'pending', transaction_id TEXT, student_email TEXT, student_national_id TEXT, timestamp TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE admin_users (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, full_name_arabic TEXT, national_id TEXT, email TEXT, mobile TEXT, registered_at TIMESTAMPTZ DEFAULT NOW(), is_admin_added BOOLEAN DEFAULT TRUE);
CREATE TABLE fee_structure (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, application_fee NUMERIC DEFAULT 200, colleges JSONB DEFAULT '{}'::jsonb, updated_at TIMESTAMPTZ DEFAULT NOW());
